+fn ordered_valid_printf_indices(table: &[PrintfRoute; 256]) -> Vec<usize> {
+    const PREFERRED_ORDER: &[u8] = b"diouxXfFeEgGaAcspn%";
+    ordered_valid_indices(PREFERRED_ORDER, |idx| {
